def calculate_average_effectiveness(feedback, treatment_name):
    # Filter feedback for the specified treatment
    treatment_ratings = [rating for patient in feedback if treatment_name in patient["treatments"]]

    # Calculate the average if there are ratings
    if treatment_ratings:
        average = sum(treatment_ratings) / len(treatment_ratings)
        return round(average, 2)
    else:
        return 0.0
